const outputText = $input.first().json.output || "";

// Extract URL using regex
const urlMatch = outputText.match(/!\[.*?\]\((.*?)\)/);
const chartUrl = urlMatch ? urlMatch[1] : "";

// Remove Markdown image format from the text
const formattedText = outputText.replace(/!\[.*?\]\(.*?\)/g, "").trim();

// Prepare message for Telegram
const telegramMessage = `📊 *Technical Analysis for AAPL*  

${formattedText}`;

return [
  {
    json: {
      message: telegramMessage,
      chartUrl: chartUrl
    }
  }
];

const messageData = $('Code').first().json.message || "";

// Debugging: Log the original message before processing
console.log("Original Message Length:", messageData.length);
console.log("Original Message:", messageData);

// Remove extra newlines while preserving necessary spacing
const cleanedMessage = messageData.replace(/\n{2,}/g, "\n").trim();

// Function to split the message into chunks of 4085 characters
function splitMessage(text, chunkSize) {
    let chunks = [];
    for (let i = 0; i < text.length; i += chunkSize) {
        chunks.push(text.slice(i, i + chunkSize));
    }
    return chunks;
}

// Split the message into multiple parts
const messageChunks = splitMessage(cleanedMessage, 4085);

// Debugging: Log the number of chunks and their lengths
console.log("Total Chunks:", messageChunks.length);
messageChunks.forEach((chunk, index) => {
    console.log(`Chunk ${index + 1} Length:`, chunk.length);
    console.log(`Chunk ${index + 1} Content:`, chunk);
});

// Return the chunks as separate JSON objects for looping in n8n
return messageChunks.map(chunk => ({ json: { message: chunk } }));

